<?php require_once dirname(__DIR__).'/includes/auth.php'; require_login(); $pageTitle='Email Logs'; $rows=db()->query('SELECT * FROM email_logs ORDER BY created_at DESC LIMIT 200')->fetchAll(); include __DIR__.'/includes/header.php'; ?>
<div class="panel"><table class="data-table"><thead><tr><th>Recipient</th><th>Subject</th><th>Status</th><th>Error</th><th>Date</th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="5" class="empty">No email logs yet.</td></tr><?php endif; foreach($rows as $r):?><tr><td><?= e($r['recipient']) ?></td><td><?= e($r['subject']) ?></td><td><span class="badge b-<?= e($r['status']) ?>"><?= e($r['status']) ?></span></td><td><?= e(mb_strimwidth($r['error_message']??'',0,120,'...')) ?></td><td><?= e(date('d M Y H:i',strtotime($r['created_at']))) ?></td></tr><?php endforeach;?></tbody></table></div>
<?php include __DIR__.'/includes/footer.php'; ?>
